@startuml
skinparam classDiagram labelStyle fontColor "C"
skinparam classDiagram labelStyle fontColor "I"
skinparam classDiagram labelStyle fontColor "A"

class Game {
    +create():AbstractEnemy
}

class EnemyFactory {
    +create():AbstractAircraft
}

class EliteFactory {
    +create():EliteEnemy
}

class BossFactory {
    +create():BossEnemy
}

class MobFactory {
    +create():MobEnemy
}

class AbstractAircraft {
    +maxHp:int
    +hp:int
    +kind:int
    +AbstractAircraft(int locationX, int locationY, int speedX, int speedY, int hp):void
    +decreaseHp(int decrease):void
    +getHp():int
    +shoot():List<BaseBullet>
}

class EliteEnemy {
    +shootNum:int
    +power:int
    +direction:int
    +kind:int
    +EliteEnemy(int locationX, int locationY, int speedX, int speedY, int hp):void
    +forward():void
    +shoot():List<BaseBullet>
    +addProp():List<AbstractProp>
}

class BossEnemy {
    +shootNum:int
    +power:int
    +direction:int
    +kind:int
    +BossEnemy(int locationX, int locationY, int speedX, int speedY, int hp):void
    +forward():void
    +shoot():List<Bullet>
    +enemyKind():int
}

class MobEnemy {
    +MobEnemy(int locationX, int locationY, int speedX, int speedY, int hp):void
    +forward():void
    +kind:int
    +shoot():List<BaseBullet>
}

Game --> EnemyFactory
EnemyFactory --> AbstractAircraft
EliteFactory --> EliteEnemy
BossFactory --> BossEnemy
MobFactory --> MobEnemy
AbstractAircraft --> EliteEnemy
AbstractAircraft --> BossEnemy
AbstractAircraft --> MobEnemy

@enduml
